mapper.select:
SELECT DATE(r.upload_time) AS date, r.department AS department, e.entity_type AS entityType, COUNT(*) AS totalEntities, SUM(CASE WHEN e.verified = 1 THEN 1 ELSE 0 END) AS verifiedEntities, SUM(CASE WHEN e.confidence IS NOT NULL AND e.confidence >= 0.8 THEN 1 ELSE 0 END) AS highConfidenceEntities, ROUND( (SUM(CASE WHEN e.verified = 1 OR (e.confidence IS NOT NULL AND e.confidence >= 0.8) THEN 1 ELSE 0 END)) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS accuracyRate FROM surgery_entity e INNER JOIN surgery_record r ON r.id = e.record_id AND r.deleted = 0 WHERE e.deleted = 0
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
AND r.department = #{department}
AND e.entity_type = #{entityType}
GROUP BY DATE(r.upload_time)
, e.entity_type
, r.department
ORDER BY date

SELECT e.entity_type AS entityType, COUNT(*) AS count, ROUND(AVG(CASE WHEN e.confidence IS NOT NULL THEN e.confidence ELSE 0 END), 4) AS avgConfidence FROM surgery_entity e INNER JOIN surgery_record r ON r.id = e.record_id AND r.deleted = 0 WHERE e.deleted = 0 AND (e.confidence IS NULL OR e.confidence < #{confidenceThreshold})
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
AND r.department = #{department}
GROUP BY e.entity_type ORDER BY count DESC
